import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.Arrays;
import java.util.Comparator;

public class Crypto {
	public static int money;
	public static int noComputers;
	public static int[][] computers;
	public static int[] sums;

	static class Task {
		public final String inputFile = "crypto.in";
		public final String outputFile = "crypto.out";

		private void readInput() {
			String[] currentLine;
			try {
				FileReader fr = new FileReader(inputFile);
				BufferedReader br = new BufferedReader(fr);
				currentLine = br.readLine().split(" ");
				noComputers = Integer.parseInt(currentLine[0]);
				money = Integer.parseInt(currentLine[1]);
				computers = new int[noComputers][2];
				sums = new int[noComputers];
				for (int i = 0; i < noComputers; i++) {
					currentLine = br.readLine().split(" ");
					computers[i][0] = Integer.parseInt(currentLine[0]);
					computers[i][1] = Integer.parseInt(currentLine[1]);
				}
				fr.close();
				br.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private void writeOutput(int result) {
			try {
				PrintWriter pw = new PrintWriter((outputFile));
				pw.printf("%d\n", result);
				pw.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		/* Populeaza vector sume partiale */
		private void getSums() {
			int sum = 0;
			for (int i = 0; i < computers.length; i++) {
				sum += computers[i][1];
				sums[i] = sum;
			}
		}

		private int getResult() {
			Arrays.sort(computers, new Comparator<int[]>() {	// sortare
				@Override
				public int compare(int[] entry1, int[] entry2) {
					if (entry1[0] > entry2[0]) {
						return 1;
					} else if (entry1[0] < entry2[0]) {
						return -1;
					} else { 
						return 0; 
					}
				}
			});
			getSums();
			int minAmount;							// retine cantitatea minima
			while (money > 0) {						// cat timp exista resurse
				int nr = 0;							// retine nr. de calculatoare
				minAmount = computers[0][0];
				for (int[] computer : computers) {
					if (computer[0] != minAmount) {
						break;
					}
					computer[0] += 1;				// upgrade
					nr++;							// numara cate calc. = min
				}
				if (money < sums[nr - 1]) {			// nu mai sunt resurse
					computers[0][0] -= 1;			// anuleaza ultimul upgrade
					break;
				} else {
					money -= sums[nr - 1];			// actualizeaza resurse
				}
			}
			return computers[0][0];					// returneaza minimul
		}

		public void solve() {
			readInput();
			writeOutput(getResult());
		}
	}


	public static void main(String[] args) {
		new Task().solve();
	}
}

