using namespace std;

bool number_coins_comp(pair<int, int>& elem1, pair<int, int>& elem2) {
	return (elem1.first < elem2.first);
}

long crypto(long N, long B, vector<pair<int, int>>& computers) {
	long costs;
	long coins;

	/* Sort the ascending vector by the first column (number of coins 
	produced in per hour). */
	sort(computers.begin(), computers.end(), number_coins_comp);

	costs = computers[0].second;
	coins = computers[0].first;

	for (int i = 1; i < N; i++) {
		if (computers[i].first > coins) {
			if ((computers[i].first - coins) * costs <= B) {
				/* It is budget enough to update all previous computers 
				to reach the current number of coins. */
				B -= (computers[i].first - coins) * costs;
				coins = computers[i].first;
			} else {
				/* It is not enought budget, so we increase the minimum 
				number of coins as much as our budget allows. */
				coins += (B / costs);
				B -= (B / costs) * costs;
				break;
			}
		}

		/* Store the cost of an update for all computers up to the current 
		one. */
		costs += computers[i].second;
	}

	if (B >= costs) {
		coins += (B / costs);
		B -= (B / costs) * costs;
	}

	return coins;
}

